use std::io;
use std::str::FromStr;

fn get_line() -> String {
    let mut input = String::new();
    io::stdin().read_line(&mut input).unwrap();
    input
}

fn get_vec<T>() -> Vec<T>
where T: FromStr,
      <T as FromStr>::Err: std::fmt::Debug,
{
    get_line().split_whitespace().map(|k| k.parse().unwrap()).collect()
}

fn main() {
    let n: usize = get_line().trim().parse().unwrap();

    let mut input = String::new();
    use std::io::Read;
    io::stdin().read_to_string(&mut input).unwrap();

    let a: Vec<u8> = input.split_whitespace()
        .map(|x| x.parse().unwrap()).collect();

    let next = |winner, spec| {
        6 - winner - spec
    };

    let specs: Vec<_> = a.iter().scan(3, |state, winner| {
        let spec = *state;
        *state = next(winner, spec);
        Some(spec)
    }).collect();

    let ans = (0..n).all(|i| a[i] != specs[i]);

    if ans {
        println!("YES");
    } else {
        println!("NO");
    }
}

